var all = $input.all();
var nc = [];
all.forEach(function(item) {
  var w = item.json;
  var hasError = w.settings && w.settings.errorWorkflow && w.settings.errorWorkflow.trim() !== '';
  if (!hasError && w.active) nc.push({ name: w.name || 'Sans nom', id: w.id || '' });
});
var message = nc.length === 0
  ? '✅ <b>Tous les workflows actifs ont une notification d\'erreur configurée</b>'
  : '⚠️ <b>' + nc.length + ' workflow(s) sans notification d\'erreur :</b>\n\n' + nc.map(function(w){ return '• ' + w.name; }).join('\n') + '\n\n💡 Ajoute un <i>Error Workflow</i> dans leurs Settings.';
return [{ json: { message } }];

const wfName = $('n8n API - Récupère tous les workflows').item.json.name;
const today = $now.toFormat('yyyy-MM-dd');
const targetName = wfName + '_' + today + '.json';
const existing = $input.all().filter(i => i.json.name === targetName && i.json.id);
if (existing.length > 0) return existing.map(i => ({ json: { id: i.json.id, doDelete: true } }));
return [{ json: { doDelete: false } }];

