const rcloneOutput = $('Execute Command - Liste dossiers Drive').item.json.stdout;

const allPaths = rcloneOutput
  .split('\n')
  .map(l => l.trim().replace(/\/$/, ''))
  .filter(Boolean);

// Niveau 1 : pas de slash dans le chemin
const niveau1 = allPaths.filter(p => !p.includes('/'));

// Niveau 2 : un slash → { "CHAT BOT": ["BOT WHAT'SAPP", ...], ... }
const niveau2 = {};
allPaths
  .filter(p => (p.match(/\//g) || []).length === 1)
  .forEach(p => {
    const [parent, child] = p.split('/');
    if (!niveau2[parent]) niveau2[parent] = [];
    niveau2[parent].push(child);
  });

const staticData = $getWorkflowStaticData('global');
staticData.niveau1 = niveau1;
staticData.niveau2 = niveau2;

return [{ json: { niveau1, niveau2 } }];

const staticData = $getWorkflowStaticData('global');
const niveau1 = staticData.niveau1 ?? [];
const niveau2 = staticData.niveau2 ?? {};

const wf = $('n8n API - Récupère tous les workflows').item.json;
const tags = wf.tags ?? [];

// tag1 = celui qui matche un dossier racine Drive
const tag1obj = tags.find(t => niveau1.includes(t.name));
const tag1 = tag1obj?.name ?? null;

// tag2 = celui qui matche un sous-dossier de tag1
const sousDossiers = tag1 ? (niveau2[tag1] ?? []) : [];
const tag2obj = tags.find(t => t !== tag1obj && sousDossiers.includes(t.name));
const tag2 = tag2obj?.name ?? null;

return [{
  json: {
    wfId:   wf.id,
    wfName: wf.name,
    tag1,
    tag2,
    hasTag2: tag2 !== null
  }
}];
